import { hasPermissionCode } from '../utils/erpPermissionCode';

const PREFIX = 'erp-finance:cost-sheets';

/**
 * Giá thành / cost sheet — Kind E job workflow (`erp-form-toolbar-permissions.md` § Tính toán).
 */
export function useCostSheetPermissions() {
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canRun: hasPermissionCode(`${PREFIX}:run`),
    canApprove: hasPermissionCode(`${PREFIX}:approve`) || hasPermissionCode(`${PREFIX}:run`),
    canPost: hasPermissionCode(`${PREFIX}:post`),
    canViewLedger: hasPermissionCode(`${PREFIX}:view-ledger`) || hasPermissionCode(`${PREFIX}:read`),
  };
}
